holder.namespaces["zkn"] = "http://www.egem.nl/StUF/sector/zkn/0310" 
holder.namespaces["stuf"] = "http://www.egem.nl/StUF/StUF0301"

def actualReferentieNummerProxySentToMockService = holder.getNodeValue("//zkn:stuurgegevens/stuf:referentienummer") 

context.getMockService().getProject().setPropertyValue("GeefZaakDetailsReferentieNummerMockServiceReceived", actualReferentieNummerProxySentToMockService)

context.getMockService().getProject().setPropertyValue("GeefLijstZaakdocumentenReferentieNummerMockServiceReceived", actualReferentieNummerProxySentToMockService)

// Both GeefZaakDetails and geefLijstZaakdocumenten requests triggers this operation of BeantwoordVraag mock service. 
// It is probably because of both messages' wrapper named "zakLv01" and SoapUI cannot distinguish them and returns the first operation.
// First operation is geefZaakDetails under BeantwoordVraag MockService.
// We use this mock operation for our test purposes for both geefZaakDetails and geefLijstZaakdocumenten.
// This problem of SoapUI doesn't impact our test verification.

return "zakLa01"

